import path from "path";
import fs from "fs";

export type DataRecord = {
  id: string;
  [key: string]: unknown;
};

const dataFile = path.join(process.cwd(), "data", "records.json");

export function readRecords(): DataRecord[] {
  if (!fs.existsSync(dataFile)) return [];
  const raw = fs.readFileSync(dataFile, "utf-8");
  return JSON.parse(raw) as DataRecord[];
}

export function writeRecords(records: DataRecord[]): void {
  fs.writeFileSync(dataFile, JSON.stringify(records, null, 2), "utf-8");
}

import { NextResponse } from "next/server";
import { readRecords, writeRecords, DataRecord } from "@/lib/dataStore";
import { randomUUID } from "crypto";

export async function GET() {
  return NextResponse.json(readRecords());
}

export async function POST(request: Request) {
  const body: Omit<DataRecord, "id"> = await request.json();
  const records = readRecords();
  const newRecord: DataRecord = { id: randomUUID(), ...body };
  records.push(newRecord);
  writeRecords(records);
  return NextResponse.json(newRecord, { status: 201 });
}

export async function DELETE() {
  writeRecords([]);
  return NextResponse.json({ ok: true });
}

import { NextResponse } from "next/server";
import { readRecords, writeRecords, DataRecord } from "@/lib/dataStore";
import ExcelJS from "exceljs";

export async function POST(request: Request) {
  const contentType = request.headers.get("content-type") ?? "";

  if (contentType.includes("application/json")) {
    const body: DataRecord[] = await request.json();
    if (!Array.isArray(body)) {
      return NextResponse.json({ error: "Expected a JSON array" }, { status: 400 });
    }
    writeRecords(body);
    return NextResponse.json({ imported: body.length });
  }

  if (
    contentType.includes("multipart/form-data") ||
    contentType.includes("application/vnd.openxmlformats")
  ) {
    const formData = await request.formData();
    const file = formData.get("file");
    if (!(file instanceof Blob)) {
      return NextResponse.json({ error: "No file uploaded" }, { status: 400 });
    }

    const buffer = Buffer.from(await file.arrayBuffer());
    const workbook = new ExcelJS.Workbook();
    await workbook.xlsx.load(buffer);
    const sheet = workbook.worksheets[0];

    const headers: string[] = [];
    const records: DataRecord[] = [];

    sheet.eachRow((row, rowIndex) => {
      if (rowIndex === 1) {
        row.eachCell((cell) => headers.push(String(cell.value ?? "")));
        return;
      }
      const record: DataRecord = { id: crypto.randomUUID() };
      row.eachCell((cell, colIndex) => {
        const key = headers[colIndex - 1];
        if (key && key !== "id") record[key] = cell.value;
      });
      records.push(record);
    });

    writeRecords(records);
    return NextResponse.json({ imported: records.length });
  }

  return NextResponse.json({ error: "Unsupported content type" }, { status: 415 });
}

import { NextResponse } from "next/server";
import { readRecords } from "@/lib/dataStore";
import ExcelJS from "exceljs";

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const format = searchParams.get("format") ?? "json";
  const records = readRecords();

  if (format === "json") {
    return new NextResponse(JSON.stringify(records, null, 2), {
      headers: {
        "Content-Type": "application/json",
        "Content-Disposition": 'attachment; filename="records.json"',
      },
    });
  }

  if (format === "xlsx") {
    const workbook = new ExcelJS.Workbook();
    const sheet = workbook.addWorksheet("Records");

    if (records.length > 0) {
      const keys = Object.keys(records[0]);
      sheet.addRow(keys);
      for (const record of records) {
        sheet.addRow(keys.map((k) => record[k]));
      }
    }

    const buffer = await workbook.xlsx.writeBuffer();
    return new NextResponse(buffer, {
      headers: {
        "Content-Type":
          "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        "Content-Disposition": 'attachment; filename="records.xlsx"',
      },
    });
  }

  return NextResponse.json({ error: "Unsupported format" }, { status: 400 });
}

"use client";

import { useEffect, useRef } from "react";
import * as d3 from "d3";

type Bar = { label: string; value: number };

export default function BarChart({ data }: { data: Bar[] }) {
  const svgRef = useRef<SVGSVGElement>(null);

  useEffect(() => {
    if (!svgRef.current || data.length === 0) return;

    const margin = { top: 20, right: 20, bottom: 40, left: 50 };
    const width = svgRef.current.clientWidth - margin.left - margin.right;
    const height = 320 - margin.top - margin.bottom;

    d3.select(svgRef.current).selectAll("*").remove();

    const svg = d3
      .select(svgRef.current)
      .attr("height", height + margin.top + margin.bottom)
      .append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    const x = d3
      .scaleBand()
      .domain(data.map((d) => d.label))
      .range([0, width])
      .padding(0.25);

    const y = d3
      .scaleLinear()
      .domain([0, d3.max(data, (d) => d.value) ?? 0])
      .nice()
      .range([height, 0]);

    svg
      .append("g")
      .attr("transform", `translate(0,${height})`)
      .call(d3.axisBottom(x))
      .selectAll("text")
      .attr("class", "text-xs fill-gray-500");

    svg.append("g").call(d3.axisLeft(y));

    svg
      .selectAll(".bar")
      .data(data)
      .join("rect")
      .attr("class", "bar")
      .attr("x", (d) => x(d.label) ?? 0)
      .attr("y", (d) => y(d.value))
      .attr("width", x.bandwidth())
      .attr("height", (d) => height - y(d.value))
      .attr("fill", "#6366f1")
      .attr("rx", 3);
  }, [data]);

  return (
    <svg
      ref={svgRef}
      className="w-full"
      aria-label="Bar chart"
      role="img"
    />
  );
}

"use client";

import { useEffect, useState } from "react";
import BarChart from "@/components/BarChart";
import type { DataRecord } from "@/lib/dataStore";

export default function VisualisePage() {
  const [records, setRecords] = useState<DataRecord[]>([]);
  const [numericKeys, setNumericKeys] = useState<string[]>([]);
  const [labelKey, setLabelKey] = useState<string>("");
  const [valueKey, setValueKey] = useState<string>("");

  useEffect(() => {
    fetch("/api/data")
      .then((r) => r.json())
      .then((data: DataRecord[]) => {
        setRecords(data);
        if (data.length === 0) return;
        const keys = Object.keys(data[0]).filter((k) => k !== "id");
        const nums = keys.filter((k) => typeof data[0][k] === "number");
        setNumericKeys(nums);
        setLabelKey(keys[0] ?? "");
        setValueKey(nums[0] ?? "");
      });
  }, []);

  const chartData = records
    .map((r) => ({
      label: String(r[labelKey] ?? ""),
      value: Number(r[valueKey] ?? 0),
    }))
    .filter((d) => d.label);

  return (
    <div className="max-w-3xl mx-auto">
      <h1 className="text-2xl font-bold mb-6">Visualise</h1>

      {records.length === 0 ? (
        <p className="text-gray-500">
          No data loaded. Import data first via the{" "}
          <a href="/import" className="text-indigo-600 underline">
            Import
          </a>{" "}
          page.
        </p>
      ) : (
        <>
          <div className="flex gap-4 mb-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Label column
              </label>
              <select
                className="border border-gray-300 rounded px-3 py-1.5 text-sm"
                value={labelKey}
                onChange={(e) => setLabelKey(e.target.value)}
              >
                {Object.keys(records[0])
                  .filter((k) => k !== "id")
                  .map((k) => (
                    <option key={k} value={k}>
                      {k}
                    </option>
                  ))}
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Value column (numeric)
              </label>
              <select
                className="border border-gray-300 rounded px-3 py-1.5 text-sm"
                value={valueKey}
                onChange={(e) => setValueKey(e.target.value)}
              >
                {numericKeys.map((k) => (
                  <option key={k} value={k}>
                    {k}
                  </option>
                ))}
              </select>
            </div>
          </div>

          <div className="bg-white rounded-xl border border-gray-200 p-6">
            <BarChart data={chartData} />
          </div>
        </>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import type { DataRecord } from "@/lib/dataStore";

export default function DataPage() {
  const [records, setRecords] = useState<DataRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [newRow, setNewRow] = useState<Record<string, string>>({});
  const [columns, setColumns] = useState<string[]>([]);

  const load = () => {
    setLoading(true);
    fetch("/api/data")
      .then((r) => r.json())
      .then((data: DataRecord[]) => {
        setRecords(data);
        if (data.length > 0) {
          setColumns(Object.keys(data[0]).filter((k) => k !== "id"));
        }
      })
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  const handleAdd = async () => {
    await fetch("/api/data", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(newRow),
    });
    setNewRow({});
    load();
  };

  const handleClear = async () => {
    if (!confirm("Clear all records?")) return;
    await fetch("/api/data", { method: "DELETE" });
    setRecords([]);
    setColumns([]);
  };

  const headers = records.length > 0 ? Object.keys(records[0]).filter((k) => k !== "id") : [];

  return (
    <div className="max-w-5xl mx-auto">
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-bold">Data</h1>
        {records.length > 0 && (
          <button
            onClick={handleClear}
            className="text-sm text-red-600 border border-red-300 px-3 py-1.5 rounded hover:bg-red-50 transition"
          >
            Clear all
          </button>
        )}
      </div>

      {loading ? (
        <p className="text-gray-400">Loading…</p>
      ) : records.length === 0 ? (
        <p className="text-gray-500">
          No records. Import data via the{" "}
          <a href="/import" className="text-indigo-600 underline">Import</a> page,
          or add a row below.
        </p>
      ) : (
        <div className="overflow-x-auto rounded-xl border border-gray-200 mb-6">
          <table className="w-full text-sm">
            <thead className="bg-gray-50">
              <tr>
                {headers.map((h) => (
                  <th key={h} className="px-4 py-2 text-left font-medium text-gray-600">
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {records.map((r) => (
                <tr key={r.id} className="hover:bg-gray-50">
                  {headers.map((h) => (
                    <td key={h} className="px-4 py-2 text-gray-800">
                      {String(r[h] ?? "")}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Add row */}
      <div className="bg-white rounded-xl border border-gray-200 p-5">
        <h2 className="font-semibold mb-3">Add a row</h2>
        {columns.length === 0 ? (
          <p className="text-sm text-gray-400">
            Import data first to define columns, then add rows here.
          </p>
        ) : (
          <div className="flex flex-wrap gap-3 mb-3">
            {columns.map((col) => (
              <div key={col} className="flex flex-col gap-1">
                <label className="text-xs text-gray-500">{col}</label>
                <input
                  className="border border-gray-300 rounded px-2 py-1 text-sm w-40"
                  value={newRow[col] ?? ""}
                  onChange={(e) =>
                    setNewRow((prev) => ({ ...prev, [col]: e.target.value }))
                  }
                />
              </div>
            ))}
            <button
              onClick={handleAdd}
              className="self-end bg-indigo-600 text-white text-sm px-4 py-1.5 rounded hover:bg-indigo-700 transition"
            >
              Add
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";

export default function ImportPage() {
  const [status, setStatus] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFile = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setStatus(null);
    setError(null);

    if (file.name.endsWith(".json")) {
      const text = await file.text();
      let parsed: unknown;
      try {
        parsed = JSON.parse(text);
      } catch {
        setError("Invalid JSON file.");
        return;
      }
      const res = await fetch("/api/import", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(parsed),
      });
      const data = await res.json();
      if (!res.ok) setError(data.error);
      else setStatus(`Imported ${data.imported} records from JSON.`);
      return;
    }

    if (file.name.endsWith(".xlsx")) {
      const form = new FormData();
      form.append("file", file);
      const res = await fetch("/api/import", { method: "POST", body: form });
      const data = await res.json();
      if (!res.ok) setError(data.error);
      else setStatus(`Imported ${data.imported} records from Excel.`);
      return;
    }

    setError("Unsupported file type. Use .xlsx or .json.");
  };

  return (
    <div className="max-w-lg mx-auto">
      <h1 className="text-2xl font-bold mb-6">Import</h1>
      <div className="bg-white rounded-xl border border-gray-200 p-6">
        <p className="text-sm text-gray-500 mb-4">
          Upload an <strong>.xlsx</strong> or <strong>.json</strong> file.
          The first row of Excel files is treated as the header. JSON files must
          be an array of objects.
        </p>
        <label className="cursor-pointer inline-block bg-indigo-600 text-white text-sm px-4 py-2 rounded hover:bg-indigo-700 transition">
          Choose file
          <input
            type="file"
            accept=".xlsx,.json"
            className="hidden"
            onChange={handleFile}
          />
        </label>

        {status && (
          <p className="mt-4 text-sm text-green-700 bg-green-50 border border-green-200 rounded px-3 py-2">
            {status}
          </p>
        )}
        {error && (
          <p className="mt-4 text-sm text-red-700 bg-red-50 border border-red-200 rounded px-3 py-2">
            {error}
          </p>
        )}
      </div>
    </div>
  );
}

